"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[5761],{49678(n,r,s){s.r(r),s.d(r,{assets:()=>c,contentTitle:()=>o,default:()=>g,frontMatter:()=>d,metadata:()=>t,toc:()=>i});const t=JSON.parse('{"id":"cpp20/ranges-basics","title":"Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)","description":"C++20 Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/20-ranges-basics.md","sourceDirName":"cpp20","slug":"/cpp20/20-ranges-basics","permalink":"/LearnModernCpp/docs/cpp20/20-ranges-basics","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"ranges_basics","permalink":"/LearnModernCpp/docs/tags/ranges-basics"}],"version":"current","sidebarPosition":21,"frontMatter":{"sidebar_position":21,"slug":"20-ranges-basics","title":"Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)","description":"C++20 Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","ranges_basics"]},"sidebar":"docs","previous":{"title":"\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)","permalink":"/LearnModernCpp/docs/cpp20/10-aggregate-parens-init"},"next":{"title":"Ranges \u89c6\u56fe (Views: filter/transform/take \u7b49)","permalink":"/LearnModernCpp/docs/cpp20/21-ranges-views"}}');var e=s(74848),a=s(28453);const d={sidebar_position:21,slug:"20-ranges-basics",title:"Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)",description:"C++20 Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","ranges_basics"]},o="Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)",c={},i=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,a.R)(),...n.components};return(0,e.jsxs)(e.Fragment,{children:[(0,e.jsx)(r.header,{children:(0,e.jsx)(r.h1,{id:"ranges-\u57fa\u7840-stdranges-\u7b97\u6cd5",children:"Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)"})}),"\n",(0,e.jsx)(r.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,e.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,e.jsx)(r.pre,{children:(0,e.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp20/20_ranges_basics.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::ranges \u547d\u540d\u7a7a\u95f4\u4e0b\u63d0\u4f9b\u4e86\u4e00\u5957\u65b0\u7684\u7b97\u6cd5\uff0c\r\n *          \u53ef\u4ee5\u76f4\u63a5\u63a5\u53d7\u5bb9\u5668\uff08\u800c\u975e\u8fed\u4ee3\u5668\u5bf9\uff09\uff0c\r\n *          \u5e76\u652f\u6301\u6295\u5f71\uff08projection\uff09\u529f\u80fd\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u4f20\u7edf STL \u7b97\u6cd5\u9700\u8981\u4f20\u9012 begin/end \u8fed\u4ee3\u5668\u5bf9\uff0c\r\n *             \u4ee3\u7801\u5197\u957f\u4e14\u5bb9\u6613\u51fa\u9519\u3002Ranges \u7b97\u6cd5\u66f4\u7b80\u6d01\u3001\u66f4\u5b89\u5168\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u76f4\u63a5\u4f20\u5bb9\u5668\uff0c\u4e0d\u9700\u8981 begin()/end()\r\n *   - \u6295\u5f71\uff08projection\uff09\u53ef\u4ee5\u5728\u7b97\u6cd5\u4e2d\u53d8\u6362\u5143\u7d20\r\n *   - \u8fd4\u56de\u66f4\u4e30\u5bcc\u7684\u4fe1\u606f\uff08\u5982 ranges::find \u8fd4\u56de\u8fed\u4ee3\u5668\uff09\r\n *   - \u7ea6\u675f\u66f4\u4e25\u683c\uff0c\u9519\u8bef\u4fe1\u606f\u66f4\u6e05\u6670\r\n * ============================================================\r\n */\r\n\r\n#include <algorithm>\r\n#include <iostream>\r\n#include <numeric>\r\n#include <ranges>\r\n#include <string>\r\n#include <vector>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\nstruct Student {\r\n    std::string name;\r\n    int age;\r\n    double score;\r\n};\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. ranges::sort \u2014 \u76f4\u63a5\u4f20\u5bb9\u5668\r\n    std::vector<int> nums = {5, 2, 8, 1, 9, 3, 7, 4, 6};\r\n\r\n    // \u4f20\u7edf\u5199\u6cd5\r\n    // std::sort(nums.begin(), nums.end());\r\n\r\n    // C++20 ranges \u5199\u6cd5\r\n    std::ranges::sort(nums);\r\n    std::cout << "\u6392\u5e8f\u540e: ";\r\n    for (int n : nums) std::cout << n << " ";\r\n    std::cout << "\\n";\r\n\r\n    // \u964d\u5e8f\u6392\u5217\r\n    std::ranges::sort(nums, std::greater{});\r\n    std::cout << "\u964d\u5e8f: ";\r\n    for (int n : nums) std::cout << n << " ";\r\n    std::cout << "\\n";\r\n\r\n    // 2. ranges::find\r\n    auto it = std::ranges::find(nums, 5);\r\n    if (it != nums.end()) {\r\n        std::cout << "\\n\u627e\u5230 5\uff0c\u4f4d\u7f6e: " << std::distance(nums.begin(), it) << "\\n";\r\n    }\r\n\r\n    // 3. ranges::count\r\n    std::vector<int> data = {1, 2, 3, 2, 4, 2, 5};\r\n    auto cnt = std::ranges::count(data, 2);\r\n    std::cout << "2 \u51fa\u73b0\u4e86 " << cnt << " \u6b21\\n";\r\n\r\n    // 4. ranges::min / ranges::max\r\n    auto min_val = std::ranges::min(nums);\r\n    auto max_val = std::ranges::max(nums);\r\n    std::cout << "\u6700\u5c0f\u503c: " << min_val << ", \u6700\u5927\u503c: " << max_val << "\\n";\r\n\r\n    // 5. ranges::for_each\r\n    std::cout << "\\nfor_each \u8f93\u51fa: ";\r\n    std::ranges::for_each(nums, [](int n) { std::cout << n * 2 << " "; });\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // ---- \u6295\u5f71 (Projection) ----\r\n    std::cout << "-- \u6295\u5f71 (Projection) --\\n";\r\n\r\n    std::vector<Student> students = {\r\n        {"\u5f20\u4e09", 20, 85.5},\r\n        {"\u674e\u56db", 22, 92.0},\r\n        {"\u738b\u4e94", 19, 78.3},\r\n        {"\u8d75\u516d", 21, 95.5},\r\n        {"\u5b59\u4e03", 20, 88.0}\r\n    };\r\n\r\n    // \u6309\u5206\u6570\u6392\u5e8f\uff08\u4f7f\u7528\u6295\u5f71\uff09\r\n    std::ranges::sort(students, std::less{}, &Student::score);\r\n    std::cout << "\u6309\u5206\u6570\u5347\u5e8f:\\n";\r\n    for (const auto& s : students) {\r\n        std::cout << "  " << s.name << " - \u5e74\u9f84:" << s.age\r\n                  << " \u5206\u6570:" << s.score << "\\n";\r\n    }\r\n\r\n    // \u6309\u5e74\u9f84\u6392\u5e8f\r\n    std::ranges::sort(students, {}, &Student::age);  // {} \u8868\u793a\u9ed8\u8ba4\u6bd4\u8f83\u5668 (less)\r\n    std::cout << "\\n\u6309\u5e74\u9f84\u5347\u5e8f:\\n";\r\n    for (const auto& s : students) {\r\n        std::cout << "  " << s.name << " - \u5e74\u9f84:" << s.age << "\\n";\r\n    }\r\n\r\n    // \u7528\u6295\u5f71\u67e5\u627e\r\n    auto found = std::ranges::find(students, "\u8d75\u516d", &Student::name);\r\n    if (found != students.end()) {\r\n        std::cout << "\\n\u627e\u5230\u8d75\u516d\uff0c\u5206\u6570: " << found->score << "\\n";\r\n    }\r\n\r\n    // \u7528\u6295\u5f71\u67e5\u627e\u6700\u9ad8\u5206\r\n    auto best = std::ranges::max_element(students, {}, &Student::score);\r\n    std::cout << "\u6700\u9ad8\u5206: " << best->name << " (" << best->score << ")\\n";\r\n\r\n    // \u6295\u5f71\u53ef\u4ee5\u662f\u4efb\u610f\u53ef\u8c03\u7528\u5bf9\u8c61\uff08Lambda\uff09\r\n    std::ranges::sort(students, {}, [](const Student& s) {\r\n        return s.name.size();  // \u6309\u540d\u5b57\u957f\u5ea6\u6392\u5e8f\r\n    });\r\n    std::cout << "\\n\u6309\u540d\u5b57\u957f\u5ea6\u6392\u5e8f:\\n";\r\n    for (const auto& s : students) {\r\n        std::cout << "  " << s.name << " (\u957f\u5ea6:" << s.name.size() << ")\\n";\r\n    }\r\n\r\n    // ---- \u4e0e\u4f20\u7edf\u7b97\u6cd5\u5bf9\u6bd4 ----\r\n    std::cout << "\\n-- \u4e0e\u4f20\u7edf\u7b97\u6cd5\u5bf9\u6bd4 --\\n";\r\n    std::vector<int> v = {3, 1, 4, 1, 5, 9, 2, 6};\r\n\r\n    // \u4f20\u7edf\uff1a\u9700\u8981\u4e24\u4e2a\u8fed\u4ee3\u5668\r\n    // std::sort(v.begin(), v.end());\r\n    // auto it = std::find(v.begin(), v.end(), 5);\r\n\r\n    // Ranges\uff1a\u76f4\u63a5\u4f20\u5bb9\u5668\r\n    std::ranges::sort(v);\r\n    auto it = std::ranges::find(v, 5);\r\n    std::cout << "\u4f20\u7edf\u7b97\u6cd5\u9700\u8981 v.begin(), v.end()\\n";\r\n    std::cout << "Ranges \u7b97\u6cd5\u76f4\u63a5\u4f20 v\\n";\r\n\r\n    // ranges::contains (C++23) \u7c7b\u4f3c\u529f\u80fd\u7528 find \u5b9e\u73b0\r\n    bool has_five = std::ranges::find(v, 5) != v.end();\r\n    std::cout << "\u662f\u5426\u5305\u542b 5: " << std::boolalpha << has_five << "\\n";\r\n\r\n    // ---- \u5176\u4ed6\u5e38\u7528 ranges \u7b97\u6cd5 ----\r\n    std::cout << "\\n-- \u5176\u4ed6\u5e38\u7528\u7b97\u6cd5 --\\n";\r\n\r\n    // ranges::all_of / any_of / none_of\r\n    std::vector<int> scores = {85, 92, 78, 95, 88};\r\n    bool all_pass = std::ranges::all_of(scores, [](int s) { return s >= 60; });\r\n    std::cout << "\u5168\u90e8\u53ca\u683c: " << all_pass << "\\n";\r\n\r\n    bool any_excellent = std::ranges::any_of(scores, [](int s) { return s >= 90; });\r\n    std::cout << "\u6709\u4eba\u4f18\u79c0: " << any_excellent << "\\n";\r\n\r\n    // ranges::copy\r\n    std::vector<int> dest;\r\n    dest.resize(scores.size());\r\n    std::ranges::copy(scores, dest.begin());\r\n    std::cout << "\u590d\u5236: ";\r\n    for (int s : dest) std::cout << s << " ";\r\n    std::cout << "\\n";\r\n\r\n    // ranges::reverse\r\n    std::ranges::reverse(dest);\r\n    std::cout << "\u53cd\u8f6c: ";\r\n    for (int s : dest) std::cout << s << " ";\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1aranges \u7b97\u6cd5\u5728 std::ranges \u547d\u540d\u7a7a\u95f4\u4e0b\r\n    std::cout << "1. ranges \u7b97\u6cd5\u5728 std::ranges \u547d\u540d\u7a7a\u95f4\u4e0b:\\n";\r\n    std::cout << "   std::sort(v.begin(), v.end());   // \u4f20\u7edf\u7b97\u6cd5\\n";\r\n    std::cout << "   std::ranges::sort(v);            // C++20 ranges \u7b97\u6cd5\\n";\r\n    std::cout << "   \u4e24\u8005\u53ef\u4ee5\u5171\u5b58\uff0c\u4e0d\u4f1a\u51b2\u7a81\\n\\n";\r\n\r\n    // \u9677\u96312\uff1a\u6295\u5f71\u4e0d\u6539\u53d8\u539f\u59cb\u6570\u636e\r\n    std::cout << "2. \u6295\u5f71\u53ea\u662f\u5728\u7b97\u6cd5\u5185\u90e8\u53d8\u6362\uff0c\u4e0d\u4fee\u6539\u539f\u59cb\u6570\u636e:\\n";\r\n    std::vector<int> nums = {-3, -1, 4, -1, 5};\r\n    std::ranges::sort(nums, {}, [](int n) { return std::abs(n); });\r\n    std::cout << "   \u6309\u7edd\u5bf9\u503c\u6392\u5e8f: ";\r\n    for (int n : nums) std::cout << n << " ";\r\n    std::cout << "\\n   \u539f\u59cb\u503c\u4fdd\u6301\u4e0d\u53d8\uff08\u4ecd\u7136\u6709\u8d1f\u6570\uff09\\n\\n";\r\n\r\n    // \u9677\u96313\uff1a\u8fd4\u56de\u503c\u4e0d\u540c\r\n    std::cout << "3. ranges \u7b97\u6cd5\u8fd4\u56de\u503c\u66f4\u4e30\u5bcc:\\n";\r\n    std::cout << "   std::sort \u8fd4\u56de void\\n";\r\n    std::cout << "   std::ranges::sort \u8fd4\u56de\u8fed\u4ee3\u5668\\n";\r\n    std::cout << "   std::ranges::find \u8fd4\u56de\u8fed\u4ee3\u5668(\u501f\u7528\u8303\u56f4\u65f6)\\n\\n";\r\n\r\n    // \u9677\u96314\uff1a\u60ac\u5782\u8fed\u4ee3\u5668\u4fdd\u62a4\r\n    std::cout << "4. ranges \u7b97\u6cd5\u9632\u6b62\u60ac\u5782\u8fed\u4ee3\u5668:\\n";\r\n    std::cout << "   auto it = std::ranges::find(get_temp_vec(), 42);\\n";\r\n    std::cout << "   // \u8fd4\u56de std::ranges::dangling \u800c\u975e\u8fed\u4ee3\u5668!\\n";\r\n    std::cout << "   \u8fd9\u662f\u4e00\u4e2a\u7f16\u8bd1\u671f\u5b89\u5168\u68c0\u67e5\\n\\n";\r\n\r\n    // \u9677\u96315\uff1aranges \u7b97\u6cd5\u4e0d\u63a5\u53d7\u6240\u6709\u5bb9\u5668\r\n    std::cout << "5. ranges \u7b97\u6cd5\u5bf9\u5bb9\u5668\u6709 concept \u7ea6\u675f:\\n";\r\n    std::cout << "   ranges::sort \u8981\u6c42 random_access_range + sortable\\n";\r\n    std::cout << "   std::list \u4e0d\u6ee1\u8db3 random_access\uff0c\u4e0d\u80fd\u7528 ranges::sort\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== Ranges \u57fa\u7840\u7b97\u6cd5 - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,e.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,e.jsxs)(r.ul,{children:["\n",(0,e.jsx)(r.li,{children:(0,e.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/ranges",children:"cppreference: Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)"})}),"\n"]})]})}function g(n={}){const{wrapper:r}={...(0,a.R)(),...n.components};return r?(0,e.jsx)(r,{...n,children:(0,e.jsx)(u,{...n})}):u(n)}},28453(n,r,s){s.d(r,{R:()=>d,x:()=>o});var t=s(96540);const e={},a=t.createContext(e);function d(n){const r=t.useContext(a);return t.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function o(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(e):n.components||e:d(n.components),t.createElement(a.Provider,{value:r},n.children)}}}]);